const DATA = [

/* ============ 8. КЛАС ============ */
{klas:8, dom:'alg', title:'Цели изрази, уравнения и неравенства (преговор)', items:[
 {t:'O', h:'Едночлен и многочлен', b:r`<p><b>Едночлен</b> е произведение от число и букви на цели неотрицателни степени; числовият множител е <b>коефициент</b>.</p><p><b>Многочлен</b> е сбор от едночлени. Подобните едночлени се събират, като се събират коефициентите им.</p>`},
 {t:'P', h:'Разкриване на скоби и разлагане', b:r`<p>При разкриване на скоби умножаваме всеки член от едната скоба с всеки член от другата и привеждаме подобните членове. Разлагането на множители е обратното действие: изнасяне на общ множител, групиране, формули за съкратено умножение.</p>`},
 {t:'F', h:'Формули за съкратено умножение', b:r`$$(a+b)^2=a^2+2ab+b^2$$ $$(a-b)^2=a^2-2ab+b^2$$ $$a^2-b^2=(a-b)(a+b)$$ $$(a+b)(a+c)=a^2+a(b+c)+bc$$`},
 {t:'Ex', h:'Пример със съкратено умножение', b:r`<p>$103^2=(100+3)^2=10000+600+9=10609$.</p>`},
 {t:'O', h:'Уравнение и корен', b:r`<p><b>Уравнение</b> с една неизвестна е равенство, съдържащо неизвестна величина. <b>Корен</b> е стойност, която превръща равенството във вярно числово равенство.</p>`},
 {t:'P', h:'Еквивалентни преобразувания', b:r`<p>Към двете страни на уравнение може да се прибавя/изважда един и същ израз; двете страни може да се умножават/делят с едно и също <b>ненулево</b> число.</p>`},
 {t:'O', h:'Неравенство и решение', b:r`<p><b>Неравенство</b> с една неизвестна съдържа знак $<$, $>$, $\le$ или $\ge$. <b>Решение</b> е всяка стойност, за която неравенството е вярно.</p>`},
 {t:'P', h:'Умножение с отрицателно число', b:r`<p>При умножение или деление на неравенство с <b>отрицателно</b> число знакът на неравенството се обръща.</p>`},
 {t:'W', h:'Проверка на неравенство', b:r`<p>При проверка на решение на неравенство е удобно интервалът да се изобрази върху числова права.</p>`}
]},

{klas:8, dom:'geo', title:'Триъгълник — основни факти (преговор)', items:[
 {t:'O', h:'Триъгълник', b:r`<p>Триъгълник е фигура, образувана от три точки, нележащи на една права, и трите отсечки между тях.</p>`},
 {t:'T', h:'Сбор на ъглите', b:r`<p>Сборът от вътрешните ъгли на триъгълник е $180^\circ$.</p>`},
 {t:'T', h:'Външен ъгъл', b:r`<p>Външен ъгъл на триъгълник е равен на сбора от двата несъседни вътрешни ъгъла. <i>Използва се</i> за бързо намиране на ъгли без третия вътрешен.</p>`},
 {t:'T', h:'Страна и срещулежащ ъгъл', b:r`<p>Срещу по-голяма страна лежи по-голям ъгъл и обратно.</p>`},
 {t:'T', h:'Неравенство на триъгълника', b:r`<p>Всяка страна е по-малка от сбора на другите две и по-голяма от тяхната разлика. <i>Използва се</i> за проверка дали триъгълник съществува.</p>`},
 {t:'O', h:'Медиана, височина, ъглополовяща', b:r`<p><b>Медиана</b> — отсечка от връх до средата на срещулежащата страна. <b>Височина</b> — перпендикуляр от връх към правата на срещулежащата страна. <b>Ъглополовяща</b> — дели ъгъла на две равни части.</p>`},
 {t:'Ex', h:'Бърза проверка', b:r`<p>Страни $4$, $7$ и $12$ см не образуват триъгълник, защото $4+7<12$.</p>`},
 {model:'tribasic', h:'Модел: ъгли и страни в триъгълник', b:'Мести два от ъглите — третият ъгъл, външният ъгъл и връзката „срещу по-голям ъгъл лежи по-голяма страна“ се преизчисляват динамично.'}
]},

{klas:8, dom:'prob', title:'Основни комбинаторни понятия', items:[
 {t:'O', h:'Основни понятия', b:r`<p><b>Възможност</b> — един допустим избор или резултат. <b>Подредба</b> — избор, при който редът има значение. <b>Неподреден избор</b> — редът няма значение.</p>`},
 {t:'O', h:'Факториел', b:r`<p>$n!=1\cdot2\cdot3\cdots n$, като $0!=1$.</p>`},
 {t:'P', h:'Правило за събиране на възможности', b:r`<p>Ако възможностите за избор на $A$ са $m$ на брой, а възможностите за избор на $B$ са $n$ на брой, то възможностите за избор на <b>$A$ или $B$</b> са $m+n$ на брой.</p>`},
 {t:'P', h:'Правило за умножаване на възможности', b:r`<p>Ако възможностите за избор на $A$ са $m$ на брой, а възможностите за избор на $B$ са $n$ на брой, то възможностите за избор на <b>$A$ и $B$</b> са $m\cdot n$ на брой.</p>`},
 {t:'O', h:'Пермутация, вариация, комбинация', b:r`<p><b>Пермутация</b> без повторение — подредба на всички $n$ различни елемента. <b>Вариация</b> $V_n^k$ — подреден избор на $k$ от $n$ елемента. <b>Комбинация</b> $C_n^k$ — неподреден избор на $k$ от $n$ елемента.</p>`},
 {t:'F', h:'Формули на комбинаториката', b:r`$$P_n=n!$$ $$V_n^k=n(n-1)\cdots(n-k+1)=\frac{n!}{(n-k)!}$$ $$C_n^k=\frac{n!}{k!\,(n-k)!}\qquad V_n^k=C_n^k\cdot k!$$`},
 {t:'W', h:'Кога какво се използва', b:r`<p>Ако редът участва в условието — вариации или пермутации. Ако се пита само <i>кои</i> елементи са избрани — комбинации.</p>`},
 {t:'Ex', h:'Пример: редът има значение', b:r`<p>От 5 ученици се избират председател и заместник: $V_5^2=5\cdot4=20$ начина, защото длъжностите са различни.</p>`},
 {t:'Ex', h:'Пример: редът няма значение', b:r`<p>От 5 ученици се избират 2 за екип: $C_5^2=10$, защото екипът $\{А,Б\}$ е същият като $\{Б,А\}$.</p>`},
 {model:'comb', h:'Модел: избор на k от n', b:'Избери какво броим и колко обекта — виждаш формулата с числата и конкретните избори, изписани един по един.'}
]},

{klas:8, dom:'geo', title:'Вектори', items:[
 {t:'O', h:'Насочена отсечка и вектор', b:r`<p><b>Насочена отсечка</b> $\vec{AB}$ има начало $A$ и край $B$. <b>Вектор</b> е множеството от всички насочени отсечки с една и съща дължина, посока и направление.</p>`},
 {t:'O', h:'Дължина и нулев вектор', b:r`<p><b>Дължина</b> на вектор е дължината на кой да е негов представител: $|\vec a|$. <b>Нулевият вектор</b> има дължина $0$ и няма определена посока.</p>`},
 {t:'O', h:'Колинеарни, равни, противоположни', b:r`<p><b>Колинеарни</b> — представителите им лежат на успоредни или съвпадащи прави. <b>Равни</b> — еднаква дължина, посока и направление. <b>Противоположни</b> — равни дължини и посоки, противоположни направления: $-\vec a$.</p>`},
 {t:'P', h:'Събиране на вектори', b:r`<p><b>Правило на триъгълника:</b> ако краят на $\vec a$ съвпада с началото на $\vec b$, то $\vec a+\vec b$ е векторът от началото на първия до края на втория. <b>Правило на успоредника:</b> при общо начало сумата е диагоналът на успоредника. <b>Изваждане:</b> $\vec a-\vec b=\vec a+(-\vec b)$.</p>`},
 {t:'O', h:'Умножение с число', b:r`<p>$k\vec a$: при $k>0$ посоката и направлението се запазват; при $k<0$ направлението се обръща; при $k=0$ се получава нулевият вектор. $$|k\vec a|=|k|\cdot|\vec a|$$</p>`},
 {t:'F', h:'Свойства на действията', b:r`$$\vec a+\vec b=\vec b+\vec a \qquad (\vec a+\vec b)+\vec c=\vec a+(\vec b+\vec c)$$ $$\vec a+\vec 0=\vec a \qquad \vec a+(-\vec a)=\vec 0$$ $$k(\vec a+\vec b)=k\vec a+k\vec b \qquad (k+m)\vec a=k\vec a+m\vec a \qquad k(m\vec a)=(km)\vec a$$`},
 {t:'T', h:'Успоредник и среда', b:r`<p>Ако $ABCD$ е успоредник: $\vec{AB}=\vec{DC}$ и $\vec{AD}=\vec{BC}$. Ако $M$ е среда на $AB$: $\vec{AM}=\vec{MB}$ и $\vec{OM}=\tfrac12(\vec{OA}+\vec{OB})$ за произволна точка $O$.</p>`},
 {t:'T', h:'Медицентър чрез вектори', b:r`<p>$G$ е медицентър на $\triangle ABC$ точно когато $\vec{OG}=\tfrac13(\vec{OA}+\vec{OB}+\vec{OC})$ за произволна точка $O$.</p>`},
 {model:'vectors', h:'Модел: действия с вектори', b:'Задай координатите на два вектора — сума по правилото на триъгълника и на успоредника, и умножение с число k.'}
]},

{klas:8, dom:'geo', title:'Триъгълник и трапец', items:[
 {t:'O', h:'Делене на отсечка. Средна отсечка', b:r`<p>Точка $M$ дели $AB$ в отношение $m:n$, ако $AM:MB=m:n$. <b>Средна отсечка</b> в триъгълник свързва средите на две негови страни.</p>`},
 {t:'T', h:'Теорема за средната отсечка', b:r`<p>Средната отсечка е успоредна на третата страна и е равна на половината от нея: ако $M,N$ са среди на $AB,AC$, то $MN\parallel BC$ и $MN=\tfrac{BC}{2}$. <i>Използва се</i> за доказване на успоредност и за намиране на дължини.</p>`},
 {t:'T', h:'Следствие', b:r`<p>Отсечка през средата на една страна, успоредна на втора страна, минава през средата на третата страна.</p>`},
 {t:'O', h:'Медицентър', b:r`<p>Медицентърът е пресечната точка на трите медиани.</p>`},
 {t:'T', h:'Свойства на медицентъра', b:r`<p>Медианите се пресичат в една точка, която дели всяка медиана в отношение $2:1$ от върха: $AG:GM=2:1$, $AG=\tfrac23 AM$, $GM=\tfrac13 AM$.</p>`},
 {t:'O', h:'Трапец', b:r`<p><b>Трапец</b> — четириъгълник с две успоредни срещуположни страни (основи); другите две са бедра. <b>Височина</b> — разстоянието между правите на основите. <b>Равнобедрен трапец</b> — с равни бедра.</p>`},
 {t:'T', h:'Равнобедрен трапец', b:r`<p>Ъглите при всяка основа са равни; диагоналите са равни.</p>`},
 {t:'T', h:'Средна отсечка на трапец', b:r`<p>Отсечката между средите на бедрата е успоредна на основите и е равна на полусбора им: $$m=\frac{a+b}{2}$$</p>`},
 {t:'Ex', h:'Пример: средна отсечка', b:r`<p>Основи $9$ см и $15$ см $\Rightarrow m=\dfrac{9+15}{2}=12$ см.</p>`},
 {model:'midseg', h:'Модел: средна отсечка и медицентър', b:'Мести върха — средната отсечка остава успоредна и равна на половината от основата, а медианите се делят 2:1. Превключи към трапец за неговата средна отсечка.'}
]},

{klas:8, dom:'alg', title:'Квадратен корен и ирационални числа', items:[
 {t:'O', h:'Рационални и ирационални числа', b:r`<p><b>Рационално</b> число се записва като дроб $\dfrac{p}{q}$, $p,q$ — цели, $q\ne0$. <b>Ирационално</b> число не може да се запише така — десетичният му запис е безкраен непериодичен.</p>`},
 {t:'O', h:'Квадратен корен', b:r`<p>$\sqrt a$ за $a\ge0$ е <b>неотрицателното</b> число, чийто квадрат е $a$: $$\sqrt a=b \iff b\ge0 \text{ и } b^2=a$$</p>`},
 {t:'W', h:'Условие за смисъл', b:r`<p>$\sqrt a$ има смисъл в реалните числа само при $a\ge0$. $\sqrt a$ винаги е неотрицателният корен: $\sqrt{25}=5$, а не $\pm5$.</p>`},
 {t:'T', h:'Свойства на корените', b:r`$$\sqrt{ab}=\sqrt a\cdot\sqrt b \quad (a\ge0,\ b\ge0)$$ $$\sqrt{\frac{a}{b}}=\frac{\sqrt a}{\sqrt b} \quad (a\ge0,\ b>0)$$ $$\sqrt{a^2}=|a| \ \text{ за всяко реално } a$$`},
 {t:'P', h:'Изнасяне и внасяне на множител', b:r`<p>Изнасяне: $\sqrt{a^2 b}=|a|\sqrt b$. Внасяне на положителен множител: $a\sqrt b=\sqrt{a^2b}$ при $a\ge0,\ b\ge0$.</p>`},
 {t:'Ex', h:'Пример: изнасяне пред корен', b:r`<p>$\sqrt{72}=\sqrt{36\cdot2}=6\sqrt2$; обратно $3\sqrt5=\sqrt{9\cdot5}=\sqrt{45}$.</p>`},
 {t:'P', h:'Действия с корени', b:r`<p>Събират се само <b>подобни</b> корени: $a\sqrt c+b\sqrt c=(a+b)\sqrt c$. Умножение: $\sqrt a\cdot\sqrt b=\sqrt{ab}$. Деление: $\dfrac{\sqrt a}{\sqrt b}=\sqrt{\dfrac{a}{b}}$. За сравняване на положителни изрази двете страни може да се повдигнат на квадрат.</p>`},
 {t:'O', h:'Рационализиране на знаменател', b:r`<p>Преобразуване, при което знаменателят става рационален израз: $$\frac{1}{\sqrt a}=\frac{\sqrt a}{a}\ (a>0) \qquad \frac{1}{a+\sqrt b}=\frac{a-\sqrt b}{a^2-b}\ (a^2\ne b)$$</p>`}
]},

{klas:8, dom:'alg', title:'Квадратни уравнения', items:[
 {t:'O', h:'Квадратно уравнение', b:r`<p>Уравнение от вида $ax^2+bx+c=0$, където $a,b,c$ са реални и $a\ne0$. $a$ — старши коефициент, $b$ — коефициент пред $x$, $c$ — свободен член. <b>Непълно</b> е, когато $b=0$ или $c=0$ (или и двете).</p>`},
 {t:'O', h:'Дискриминанта', b:r`<p>$D=b^2-4ac$ — определя броя на реалните корени.</p>`},
 {t:'F', h:'Формула за корените', b:r`$$D=b^2-4ac$$ $$D>0:\ x_{1,2}=\frac{-b\pm\sqrt D}{2a} \qquad D=0:\ x=-\frac{b}{2a} \qquad D<0:\ \text{няма реални корени}$$`},
 {t:'Ex', h:'Пример с числа', b:r`<p>$x^2-5x+6=0$: $D=25-24=1$, $x_{1,2}=\dfrac{5\pm1}{2}$, т.е. $x_1=2$, $x_2=3$.</p>`},
 {t:'P', h:'Съкратена формула при четно b', b:r`<p>Ако $b=2k$: $$D_1=k^2-ac \qquad x_{1,2}=\frac{-k\pm\sqrt{D_1}}{a}$$</p>`},
 {t:'P', h:'Непълни квадратни уравнения', b:r`<p>$ax^2+c=0 \Rightarrow x^2=-\dfrac{c}{a}$ (реални корени само при $-\tfrac{c}{a}\ge0$). $ax^2+bx=0 \Rightarrow x(ax+b)=0$, т.е. $x=0$ или $ax+b=0$. $ax^2=0$ има единствен корен $x=0$.</p>`},
 {t:'T', h:'Разлагане на квадратен тричлен', b:r`<p>Ако $x_1,x_2$ са корени, то $$ax^2+bx+c=a(x-x_1)(x-x_2)$$ <i>Използва се</i> при съкращаване на дроби и решаване на неравенства.</p>`},
 {t:'T', h:'Формули на Виет', b:r`<p>Ако $x_1,x_2$ са корени на $ax^2+bx+c=0$: $$x_1+x_2=-\frac{b}{a} \qquad x_1x_2=\frac{c}{a}$$ За $x^2+px+q=0$: $x_1+x_2=-p$, $x_1x_2=q$. <b>Обратна теорема:</b> числа със сбор $-\tfrac{b}{a}$ и произведение $\tfrac{c}{a}$ са корени на уравнението.</p>`},
 {t:'Ex', h:'Пример с Виет', b:r`<p>$x^2-7x+10=0$: търсим числа със сбор $7$ и произведение $10$ — това са $2$ и $5$.</p>`},
 {t:'O', h:'Биквадратно уравнение', b:r`<p>$ax^4+bx^2+c=0$. Решава се с полагане $t=x^2,\ t\ge0$. При уравнения от по-висока степен често се търси полагане, водещо до квадратно уравнение.</p>`},
 {t:'P', h:'Алгоритъм за текстова задача', b:r`<p>① Избери неизвестна и запиши допустимите стойности. ② Състави уравнение по текста. ③ Реши го. ④ Провери кои корени са допустими. ⑤ Отговори с мерни единици.</p>`},
 {model:'quadroots', h:'Модел: корени и дискриминанта', b:'Мести коефициентите и наблюдавай как броят на реалните корени зависи от знака на D — корените са пресечните точки на параболата с оста Ox.'}
]},

{klas:8, dom:'geo', title:'Окръжност', items:[
 {t:'O', h:'Окръжност и кръг', b:r`<p><b>Окръжност</b> с център $O$ и радиус $R$ — всички точки на разстояние $R$ от $O$. <b>Кръг</b> — всички точки на разстояние не по-голямо от $R$.</p>`},
 {t:'O', h:'Радиус, диаметър, хорда, дъга', b:r`<p><b>Радиус</b> — отсечка от центъра до точка от окръжността. <b>Диаметър</b> — хорда през центъра. <b>Хорда</b> — отсечка с краища върху окръжността. <b>Дъга</b> — част от окръжността между две нейни точки.</p>`},
 {t:'O', h:'Секателна и допирателна', b:r`<p><b>Секателна</b> — права с две общи точки с окръжността. <b>Допирателна</b> — права с точно една обща точка.</p>`},
 {t:'T', h:'Взаимно положение точка–окръжност', b:r`<p>Ако $OM<R$ — точката е вътрешна; $OM=R$ — лежи на окръжността; $OM>R$ — външна.</p>`},
 {t:'T', h:'Взаимно положение права–окръжност', b:r`<p>Ако разстоянието $d$ от центъра до правата: $d<R$ — секателна; $d=R$ — допирателна; $d>R$ — няма общи точки.</p>`},
 {t:'T', h:'Допирателна и радиус', b:r`<p>Допирателната е перпендикулярна на радиуса към точката на допиране. От външна точка се построяват две допирателни отсечки и те са равни. <i>Използва се</i> при задачи с вписани окръжности.</p>`},
 {t:'O', h:'Централен и вписан ъгъл', b:r`<p><b>Централен ъгъл</b> — с връх в центъра. <b>Вписан ъгъл</b> — с връх върху окръжността, чиито рамена я пресичат.</p>`},
 {t:'T', h:'Мярка на централен и вписан ъгъл', b:r`<p>Централният ъгъл е равен на съответната дъга. Вписаният ъгъл е равен на <b>половината</b> от дъгата, на която се опира. <i>Използва се</i> постоянно при ъгли в окръжност.</p>`},
 {t:'T', h:'Следствия за вписани ъгли', b:r`<p>Вписани ъгли върху една и съща дъга са равни. Вписан ъгъл върху диаметър е прав ($90^\circ$).</p>`},
 {t:'T', h:'Хорди и диаметри', b:r`<p>Равни хорди стягат равни дъги и равни централни ъгли (и обратно). Диаметър $\perp$ хорда я разполовява заедно с дъгите ѝ; диаметър през средата на хорда (различна от диаметър) е перпендикулярен на нея.</p>`},
 {t:'T', h:'Ъгъл между допирателна и хорда', b:r`<p>Равен е на вписания ъгъл, опиращ се на съответната дъга (т.е. на половината от дъгата).</p>`},
 {t:'T', h:'Ъгли с връх вътре и вън', b:r`<p>Ъгъл с връх <b>вътре</b> в окръжността $=\tfrac12$(сбор на двете пресичани дъги). Ъгъл с връх <b>вън</b> $=\tfrac12$(разлика на дъгите).</p>`},
 {t:'O', h:'Две окръжности', b:r`<p>Могат да нямат общи точки, да се допират (една обща точка) или да се пресичат (две общи точки). <b>Концентрични</b> — с общ център. <b>Обща допирателна</b> — права, допирателна и към двете.</p>`},
 {t:'W', h:'Задачи с две окръжности', b:r`<p>Сравнявай отсечката между центровете с $R+r$ и $|R-r|$ — това определя взаимното положение.</p>`},
 {model:'circle', h:'Модел: ъгли в окръжност', b:'Променяй дъгата и мести върха на вписания ъгъл — централният ъгъл е равен на дъгата, а вписаният е наполовина.'},
 {model:'circleangles', h:'Модел: всички ъгли, свързани с окръжност', b:'Превключвай между централен, вписан, допирателна–хорда, ъгъл между две хорди (връх вътре), между две секущи (връх вън) и допирателна–секуща; мести точките и виж връзката с дъгите.'},
 {model:'circlepoint', h:'Модел: точка и окръжност', b:'Влачи точката — според разстоянието OM спрямо R тя е вътрешна, лежи върху окръжността или е външна.'},
 {model:'circleline', h:'Модел: права и окръжност', b:'Влачи правата — според разстоянието d от центъра тя е секуща (2 общи точки), допирателна (1 точка) или без общи точки.'},
 {model:'twocircles', h:'Модел: две окръжности', b:'Влачи втория център и променяй радиусите — сравни разстоянието d между центровете с R+r и |R−r|, за да определиш взаимното положение.'}
]},

{klas:8, dom:'alg', title:'Рационални изрази и дробни уравнения', items:[
 {t:'O', h:'Рационален израз и рационална дроб', b:r`<p><b>Рационален израз</b> — получен от числа и променливи чрез събиране, изваждане, умножение, деление и степенуване с естествен показател. <b>Рационална дроб</b> — дроб с многочлени в числителя и знаменателя.</p>`},
 {t:'O', h:'Дефиниционно множество', b:r`<p>Всички стойности на променливата, за които изразът има смисъл. За $\dfrac{A(x)}{B(x)}$ условието е $B(x)\ne0$.</p>`},
 {t:'W', h:'Знаменателят никога не е 0', b:r`<p>Преди всяко преобразуване запиши стойностите, които анулират знаменателите, и ги изключи.</p>`},
 {t:'P', h:'Преобразуване на дроби', b:r`<p>Основно свойство: числителят и знаменателят може да се умножат/разделят с един и същ ненулев множител. Съкращава се само с <b>множители</b>, не със събираеми. Общ знаменател = произведение от всички различни неразложими множители с най-големите им степени.</p>`},
 {t:'F', h:'Действия с рационални дроби', b:r`$$\frac{A}{B}=\frac{A\cdot C}{B\cdot C}\ (B,C\ne0) \qquad \frac{A}{B}+\frac{C}{B}=\frac{A+C}{B}$$ $$\frac{A}{B}\cdot\frac{C}{D}=\frac{AC}{BD} \qquad \frac{A}{B}:\frac{C}{D}=\frac{A}{B}\cdot\frac{D}{C}\ (C,D\ne0)$$`},
 {t:'O', h:'Дробно уравнение', b:r`<p>Уравнение, в което неизвестната участва в знаменател.</p>`},
 {t:'P', h:'Алгоритъм за дробно уравнение', b:r`<p>① Намери и изключи стойностите, анулиращи знаменателите. ② Намери най-малък общ знаменател. ③ Умножи двете страни по него. ④ Реши полученото уравнение. ⑤ Провери допустимостта на корените.</p>`},
 {t:'W', h:'Проверка на корените', b:r`<p>Корен, който анулира знаменател, е <b>недопустим</b> и се отхвърля.</p>`}
]},

{klas:8, dom:'geo', title:'Вписани и описани многоъгълници', items:[
 {t:'O', h:'Описана окръжност', b:r`<p>Окръжност през трите върха на триъгълник се нарича <b>описана</b> около него. Центърът ѝ е пресечната точка на симетралите на страните.</p>`},
 {t:'T', h:'Симетрали', b:r`<p>Симетралите на страните на триъгълник се пресичат в една точка.</p>`},
 {t:'W', h:'Къде е центърът на описаната окръжност', b:r`<p>При остроъгълен триъгълник — вътрешна точка; при правоъгълен — средата на хипотенузата; при тъпоъгълен — външна точка.</p>`},
 {t:'O', h:'Вписана и външновписана окръжност', b:r`<p><b>Вписана</b> — допира се до трите страни; центърът ѝ е пресечната точка на ъглополовящите. <b>Външновписана</b> — допира се до една страна и до продълженията на другите две.</p>`},
 {t:'T', h:'Ъглополовящи', b:r`<p>Ъглополовящите на вътрешните ъгли се пресичат в една точка. Всяка точка от ъглополовящата е на равни разстояния от раменете на ъгъла.</p>`},
 {t:'O', h:'Ортоцентър', b:r`<p>Пресечната точка на височините. Височините на триъгълник се пресичат в една точка.</p>`},
 {t:'W', h:'Забележителни точки', b:r`<p>Четирите основни: медицентър, ортоцентър, център на описаната и център на вписаната окръжност.</p>`},
 {t:'O', h:'Вписан и описан четириъгълник', b:r`<p><b>Вписан</b> — четирите му върха лежат на една окръжност. <b>Описан</b> — четирите му страни са допирателни към една окръжност.</p>`},
 {t:'T', h:'Вписан четириъгълник', b:r`<p>Сборът от срещуположните ъгли е $180^\circ$: $\angle A+\angle C=180^\circ$, $\angle B+\angle D=180^\circ$. Обратно: ако в изпъкнал четириъгълник два срещуположни ъгъла имат сбор $180^\circ$, около него може да се опише окръжност.</p>`},
 {t:'T', h:'Описан четириъгълник', b:r`<p>Сборовете от срещуположните страни са равни: $AB+CD=BC+AD$. Обратно: ако сборовете на двете двойки срещуположни страни са равни, в четириъгълника може да се впише окръжност.</p>`},
 {model:'incircle', h:'Модел: забележителни точки в триъгълник', b:'Влачи трите върха и направи триъгълника остроъгълен, правоъгълен или тъпоъгълен — виж как се разместват вписаната и описаната окръжност, медицентърът G и ортоцентърът H.'}
]},

{klas:8, dom:'geo', title:'Еднаквости в равнината', items:[
 {t:'O', h:'Преобразувание и еднаквост', b:r`<p><b>Преобразувание</b> задава на всяка точка нейна образна точка. <b>Еднаквост</b> — преобразувание, което запазва разстоянията между точките.</p>`},
 {t:'T', h:'Какво запазва еднаквостта', b:r`<p>Образът на отсечка е равна отсечка, на ъгъл — равен ъгъл, на триъгълник — еднакъв триъгълник.</p>`},
 {t:'O', h:'Движение и отражение', b:r`<p><b>Движение</b> — еднаквост, запазваща ориентацията. <b>Отражение</b> — еднаквост, променяща ориентацията.</p>`},
 {t:'O', h:'Осева симетрия', b:r`<p>С ос $g$: всяка точка $X$ се преобразува в $X'$ така, че $g$ е симетрала на $XX'$. Точките от оста са неподвижни. Фигура е <b>симетрична</b> относно $g$, ако симетрията я преобразува в самата нея.</p>`},
 {t:'W', h:'Оси на симетрия', b:r`<p>Всеки диаметър е ос на симетрия на окръжността. Равнобедреният триъгълник има ос през върха и средата на основата.</p>`},
 {t:'O', h:'Ротация и централна симетрия', b:r`<p><b>Ротация</b> с център $O$ и ъгъл $\alpha$ завърта всяка точка около $O$ на един и същ ъгъл в една и съща посока. <b>Централна симетрия</b> — ротация на $180^\circ$: $O$ е среда на $XX'$. Тя е движение (запазва ориентацията).</p>`},
 {t:'O', h:'Транслация', b:r`<p>С вектор $\vec t$: всяка точка $X$ отива в $X'$ така, че $\vec{XX'}=\vec t$. Всяка права се преобразува в успоредна или в самата себе си. Запазва дължини, ъгли, успоредност и лице.</p>`},
 {t:'W', h:'Бързо сравнение', b:r`<p>Осева симетрия — има ос, обръща ориентацията. Ротация — център и ъгъл, запазва ориентацията. Централна симетрия — ротация на $180^\circ$. Транслация — задава се с вектор, всички точки се местят еднакво.</p>`},
 {model:'transforms', h:'Модел: еднаквости в равнината', b:'Избери преобразувание — осева симетрия, ротация, централна симетрия или транслация — и наблюдавай образа на триъгълника.'}
]},

{klas:8, dom:'sum', title:'Справочник — 8. клас (най-важното)', items:[
 {t:'R', h:'Квадратен корен и съкратено умножение', b:r`<p>$\sqrt{a^2}=|a|$, $\sqrt{ab}=\sqrt{a}\,\sqrt{b}$, $\sqrt{\dfrac{a}{b}}=\dfrac{\sqrt{a}}{\sqrt{b}}$ ($a\ge0,\ b>0$).</p><p>$(a\pm b)^2=a^2\pm2ab+b^2$, $\ a^2-b^2=(a-b)(a+b)$, $\ a^3\pm b^3=(a\pm b)(a^2\mp ab+b^2)$.</p>`},
 {t:'R', h:'Геометрия — Питагор, линейна функция', b:r`<p>Питагор: $c^2=a^2+b^2$. Линейна функция $y=ax+b$: наклон $a$, нула $x=-\dfrac{b}{a}$, пресича $Oy$ в $(0;b)$.</p>`},
 {t:'R', h:'Окръжност и забележителни точки', b:r`<p>Централен ъгъл $=$ дъгата; вписан ъгъл $=\dfrac12$ от дъгата; ъгъл, вписан в полуокръжност $=90^\circ$; допирателната е $\perp$ на радиуса.</p><p>Център на <b>описаната</b> — симетралите; на <b>вписаната</b> — ъглополовящите; <b>медицентър</b> — медианите ($2:1$); <b>ортоцентър</b> — височините.</p><p>Вписан четириъгълник: $\angle A+\angle C=180^\circ$. Описан: $AB+CD=BC+AD$.</p>`}
]},

/* ============ 9. КЛАС ============ */
{klas:9, dom:'prob', title:'Множества, събития и класическа вероятност', items:[
 {t:'O', h:'Множество и подмножество', b:r`<p><b>Множество</b> — съвкупност от обекти (елементи); $x\in A$ / $x\notin A$. $A\subseteq B$, ако всеки елемент на $A$ е елемент и на $B$.</p>`},
 {t:'O', h:'Операции с множества', b:r`<p><b>Обединение</b> $A\cup B$ — елементите на $A$ <i>или</i> $B$. <b>Сечение</b> $A\cap B$ — елементите и на двете. <b>Разлика</b> $A\setminus B$ — елементите на $A$, които не са в $B$.</p>`},
 {t:'O', h:'Видове събития', b:r`<p><b>Случайно</b> — не може предварително да се каже дали ще настъпи. <b>Достоверно</b> — настъпва винаги; <b>невъзможно</b> — никога. <b>Противоположно</b> на $A$ е $\bar A$ — настъпва точно когато $A$ не настъпва. <b>Несъвместими</b> — не могат да настъпят едновременно: $A\cap B=\varnothing$.</p>`},
 {t:'F', h:'Класическа вероятност', b:r`<p>При равновъзможни изходи: $$P(A)=\frac{m}{n}$$ $m$ — благоприятни изходи, $n$ — всички изходи.</p>`},
 {t:'Ex', h:'Пример със зар', b:r`<p>Вероятност да се падне четно число при хвърляне на зар: $P=\dfrac{3}{6}=\dfrac12$.</p>`},
 {t:'T', h:'Основни свойства', b:r`$$0\le P(A)\le1 \qquad P(\text{достоверно})=1 \qquad P(\text{невъзможно})=0$$ $$P(\bar A)=1-P(A)$$`},
 {t:'T', h:'Вероятност на обединение', b:r`<p>За несъвместими събития: $P(A\cup B)=P(A)+P(B)$. За произволни: $$P(A\cup B)=P(A)+P(B)-P(A\cap B)$$ <i>Използва се</i>, когато събитията могат да настъпят едновременно.</p>`},
 {model:'venn', h:'Модел: диаграма на Вен', b:'Променяй P(A), P(B) и P(A∩B) и наблюдавай обединението и сечението на събитията.'}
]},

{klas:9, dom:'fn', title:'Функции. Линейна и квадратна функция', items:[
 {t:'O', h:'Функция', b:r`<p>Функция $f$ от $D$ в $E$ е правило, което на всяко $x\in D$ съпоставя <b>точно един</b> елемент $y\in E$; запис $y=f(x)$.</p>`},
 {t:'O', h:'Дефиниционно множество и множество от стойности', b:r`<p>$D(f)$ — допустимите стойности на аргумента; $E(f)$ — всички стойности $y=f(x)$, които функцията приема.</p>`},
 {t:'O', h:'Графика и нули', b:r`<p><b>Графика</b> — множеството от точки $M(x;f(x))$. <b>Нула</b> на функция — стойност $x$, за която $f(x)=0$ (абсцисите на пресечните точки с $Ox$).</p>`},
 {t:'O', h:'Растяща и намаляваща', b:r`<p>Растяща в интервал: от $x_1<x_2$ следва $f(x_1)<f(x_2)$; намаляваща: $f(x_1)>f(x_2)$.</p>`},
 {t:'F', h:'Линейна функция', b:r`<p>$$y=ax+b$$ При $a>0$ — расте; при $a<0$ — намалява; при $a=0$ — постоянна. Пресича $Oy$ в $(0;b)$.</p>`},
 {t:'F', h:'Квадратна функция', b:r`<p>$$y=ax^2+bx+c,\quad a\ne0$$ Графиката е парабола: при $a>0$ — отворена нагоре, при $a<0$ — надолу.</p>`},
 {t:'F', h:'Връх и ос на симетрия', b:r`$$x_v=-\frac{b}{2a} \qquad y_v=f(x_v) \qquad \text{ос: } x=-\frac{b}{2a}$$`},
 {t:'Ex', h:'Пример: връх', b:r`<p>$y=x^2-4x+1$: $x_v=\dfrac{4}{2}=2$, $y_v=4-8+1=-3$ — връх $(2;-3)$, минимум.</p>`},
 {t:'P', h:'Графично решаване', b:r`<p>Решенията на $f(x)=g(x)$ са абсцисите на пресечните точки на графиките $y=f(x)$ и $y=g(x)$.</p>`},
 {model:'linear', h:'Модел: линейна функция', b:'Плъзгачи за a и b — наблюдавай наклона и пресечната точка с Oy.'},
 {model:'quad', h:'Модел: квадратна функция', b:'Плъзгачи за a, b и c — връх, ос на симетрия, посока на отваряне и връзка с дискриминантата.'}
]},

{klas:9, dom:'alg', title:'Системи линейни уравнения с две неизвестни', items:[
 {t:'O', h:'Решение на система', b:r`<p>Наредена двойка $(x;y)$, която удовлетворява едновременно всички уравнения в системата.</p>`},
 {t:'P', h:'Метод на заместване', b:r`<p>Изразяваме едната неизвестна от едно уравнение и заместваме в другото.</p>`},
 {t:'P', h:'Метод на събиране', b:r`<p>Умножаваме уравненията по подходящи числа така, че при събиране една неизвестна да се унищожи.</p>`},
 {t:'P', h:'Метод на полагане', b:r`<p>Въвежда се нова неизвестна за повтарящ се израз — системата се свежда до по-прост вид.</p>`},
 {t:'W', h:'Проверка', b:r`<p>Намерените стойности се проверяват в първоначалната система, особено ако са правени преобразувания с ограничения.</p>`},
 {t:'S', h:'Специални случаи (геометричен смисъл)', b:r`<p>Правите се <b>пресичат</b> — едно решение (определена система). <b>Успоредни различни</b> — няма решение (несъвместима). <b>Съвпадат</b> — безброй решения (зависими уравнения).</p>`},
 {model:'system', h:'Модел: система от две линейни уравнения', b:'Мести коефициентите на двете прави и наблюдавай: една пресечна точка, успоредни прави или съвпадащи прави.'}
]},

{klas:9, dom:'alg', title:'Системи уравнения от втора степен', items:[
 {t:'O', h:'Система от втора степен', b:r`<p>Система, в която поне едно уравнение съдържа член от втора степен.</p>`},
 {t:'P', h:'Линейно + квадратно', b:r`<p>Когато едното уравнение е линейно, най-често се използва заместване — получава се квадратно уравнение.</p>`},
 {t:'P', h:'Симетрични системи', b:r`<p>Използват се полагания $S=x+y$, $P=xy$ или други подходящи изрази.</p>`},
 {t:'W', h:'Брой решения', b:r`<p>Определя се след връщане към първоначалните неизвестни — полагането може да носи допълнителни ограничения.</p>`}
]},

{klas:9, dom:'geo', title:'Подобни триъгълници', items:[
 {t:'O', h:'Пропорционални отсечки', b:r`<p>Две отсечки са пропорционални на други две, ако отношението на първите две е равно на отношението на другите две.</p>`},
 {t:'T', h:'Теорема на Талес', b:r`<p>Права, успоредна на страна на триъгълник, която пресича другите две страни, отсича върху тях пропорционални отсечки. <b>Обратна:</b> ако правата отсича пропорционални отсечки, тя е успоредна на третата страна. <i>Използва се</i> за намиране на дължини без измерване.</p>`},
 {t:'T', h:'Свойство на ъглополовящата', b:r`<p>Ъглополовящата разделя срещулежащата страна на части, пропорционални на прилежащите страни: $\dfrac{BL}{LC}=\dfrac{AB}{AC}$.</p>`},
 {t:'O', h:'Подобни триъгълници', b:r`<p>Триъгълници с равни съответни ъгли и пропорционални съответни страни. <b>Коефициент на подобност</b> $k$ — отношението на две съответни страни.</p>`},
 {t:'T', h:'Признаци за подобност', b:r`<p>① Два ъгъла от единия са равни на два ъгъла от другия. ② Две страни са пропорционални и ъглите между тях са равни. ③ Трите страни са пропорционални на трите страни на другия.</p>`},
 {t:'T', h:'Отношения в подобни триъгълници', b:r`<p>Съответните височини, медиани, ъглополовящи, периметри и радиуси на вписани/описани окръжности се отнасят както страните ($k$), а лицата — като $k^2$: $$\frac{S_1}{S_2}=k^2$$</p>`},
 {t:'Ex', h:'Пример с лица', b:r`<p>Ако $k=3$, лицето на по-големия триъгълник е $3^2=9$ пъти по-голямо.</p>`},
 {model:'thales', h:'Модел: теорема на Талес', b:'Мести успоредната права и сравнявай отношенията на отсечките по двете страни.'},
 {model:'bisector', h:'Модел: ъглополовяща в триъгълник', b:'Променяй страните AB и AC — ъглополовящата дели BC точно в отношение AB : AC.'}
]},

{klas:9, dom:'alg', title:'Рационални неравенства. Метод на интервалите', items:[
 {t:'O', h:'Числов интервал', b:r`<p>Множество от реални числа между две граници: отворен, затворен, полуотворен или безкраен интервал.</p>`},
 {t:'P', h:'Модулни неравенства', b:r`<p>$|ax+b|<c$ при $c>0$ $\iff$ $-c<ax+b<c$ (при $c\le0$ няма решение). $|ax+b|>c$ при $c>0$ $\iff$ $ax+b<-c$ или $ax+b>c$.</p>`},
 {t:'P', h:'Квадратно неравенство', b:r`<p>$ax^2+bx+c>0$ се решава чрез корените и знака на параболата или чрез метода на интервалите.</p>`},
 {t:'P', h:'Метод на интервалите', b:r`<p>① Намират се нулите и недопустимите стойности. ② Числовата ос се разделя на интервали. ③ Определя се знакът във всеки интервал. ④ Избират се интервалите според знака на неравенството.</p>`},
 {t:'W', h:'Чести капани', b:r`<p>Нулите на знаменателя <b>никога</b> не се включват в решението. При корен с четна кратност знакът не се сменя; при нечетна — се сменя.</p>`},
 {model:'intervals', h:'Модел: метод на интервалите', b:'Мести до пет корена върху числовата ос — при съвпадащи корени кратността се отчита: през корен с четна кратност знакът не се сменя.'}
]},

{klas:9, dom:'geo', title:'Метрични зависимости в правоъгълен триъгълник', items:[
 {t:'T', h:'Теорема на Питагор', b:r`<p>В правоъгълен триъгълник: $$c^2=a^2+b^2$$ квадратът на хипотенузата е сборът от квадратите на катетите. <b>Обратна:</b> ако за най-голямата страна $c$ е изпълнено $c^2=a^2+b^2$, триъгълникът е правоъгълен. <i>Използва се</i> за намиране на страна и за проверка на прав ъгъл.</p>`},
 {t:'Ex', h:'Пример: 3–4–5', b:r`<p>$a=3,\ b=4$: $c=\sqrt{9+16}=\sqrt{25}=5$.</p>`},
 {t:'T', h:'Катетова и височинна теорема', b:r`<p>Ако $\angle C=90^\circ$, $CD=h$ към $AB$, $AD=p$, $DB=q$, $AB=c$: $$a^2=cq \qquad b^2=cp \qquad h^2=pq$$ Катетът на квадрат = хипотенузата × проекцията му; височината на квадрат = произведението на проекциите.</p>`},
 {t:'F', h:'Разстояние между точки', b:r`$$AB=\sqrt{(x_2-x_1)^2+(y_2-y_1)^2}$$`},
 {t:'T', h:'Хорди, секущи и допирателни', b:r`<p>За пресичащи се хорди: $PA\cdot PB=PC\cdot PD$. За секуща и допирателна от външна точка: $PT^2=PA\cdot PB$.</p>`},
 {model:'pythagoras', h:'Модел: теорема на Питагор', b:'Променяй катетите — хипотенузата се пресмята динамично, а квадратите върху страните показват равенството на лицата.'}
]},

{klas:9, dom:'trig', title:'Тригонометрични функции на остър ъгъл', items:[
 {t:'O', h:'Определения в правоъгълен триъгълник', b:r`$$\sin\alpha=\frac{\text{срещулежащ катет}}{\text{хипотенуза}} \qquad \cos\alpha=\frac{\text{прилежащ катет}}{\text{хипотенуза}}$$ $$\tg\alpha=\frac{\text{срещулежащ катет}}{\text{прилежащ катет}} \qquad \cotg\alpha=\frac{\text{прилежащ катет}}{\text{срещулежащ катет}}$$`},
 {t:'F', h:'Основни тъждества', b:r`$$\sin^2\alpha+\cos^2\alpha=1 \qquad \tg\alpha=\frac{\sin\alpha}{\cos\alpha} \qquad \cotg\alpha=\frac{\cos\alpha}{\sin\alpha} \qquad \tg\alpha\cdot\cotg\alpha=1$$`},
 {t:'F', h:'Допълнителни ъгли', b:r`$$\sin(90^\circ-\alpha)=\cos\alpha \qquad \cos(90^\circ-\alpha)=\sin\alpha$$ $$\tg(90^\circ-\alpha)=\cotg\alpha \qquad \cotg(90^\circ-\alpha)=\tg\alpha$$`},
 {t:'F', h:'Таблични стойности', b:r`$$\begin{array}{c|cccc} \alpha & \sin\alpha & \cos\alpha & \tg\alpha & \cotg\alpha\\ \hline 30^\circ & \tfrac12 & \tfrac{\sqrt3}{2} & \tfrac{\sqrt3}{3} & \sqrt3\\ 45^\circ & \tfrac{\sqrt2}{2} & \tfrac{\sqrt2}{2} & 1 & 1\\ 60^\circ & \tfrac{\sqrt3}{2} & \tfrac12 & \sqrt3 & \tfrac{\sqrt3}{3} \end{array}$$`},
 {t:'P', h:'Решаване на правоъгълен триъгълник', b:r`<p>Избира се тригонометрична функция, която свързва дадените елементи с търсения.</p>`},
 {t:'S', h:'Отношенията зависят само от ъгъла', b:r`<p>Стойностите на $\sin\alpha,\ \cos\alpha,\ \tg\alpha,\ \cotg\alpha$ зависят единствено от големината на ъгъла $\alpha$, но не и от размерите на триъгълника: всички подобни правоъгълни триъгълници с един и същ остър ъгъл дават <b>едно и също</b> отношение на съответните страни.</p>`},
 {model:'trigright', h:'Модел: тригонометрия на остър ъгъл', b:'Влачи ъгловата точка, за да смениш ъгъла α, и върха C по хипотенузата, за да смениш само дължините — виж как sin, cos и tg зависят единствено от ъгъла, а не от размера.'}
]},

{klas:9, dom:'sum', title:'Справочник — 9. клас (най-важното)', items:[
 {t:'R', h:'Квадратно уравнение и функция', b:r`<p>$ax^2+bx+c=0$: $D=b^2-4ac$, $x_{1,2}=\dfrac{-b\pm\sqrt{D}}{2a}$. Формули на Виет: $x_1+x_2=-\dfrac{b}{a}$, $x_1x_2=\dfrac{c}{a}$.</p><p>Квадратна функция $y=ax^2+bx+c$: връх при $x=-\dfrac{b}{2a}$; параболата се отваря нагоре при $a>0$ и надолу при $a<0$.</p>`},
 {t:'R', h:'Подобие и правоъгълен триъгълник', b:r`<p>Подобни триъгълници: съответните ъгли са равни, а страните — пропорционални (коефициент $k$); лицата се отнасят като $k^2$.</p><p>Метрични зависимости: $h^2=p\cdot q$; катет$^2=$ проекция $\cdot$ хипотенуза.</p>`},
 {t:'R', h:'Тригонометрия на остър ъгъл и интервали', b:r`<p>$\sin\alpha=\dfrac{\text{срещу}}{\text{хип.}}$, $\cos\alpha=\dfrac{\text{прил.}}{\text{хип.}}$, $\tg\alpha=\dfrac{\text{срещу}}{\text{прил.}}$ — зависят само от ъгъла.</p><p>Рационални неравенства се решават с <b>метода на интервалите</b>: нули на числителя и знаменателя, знак по интервали.</p>`}
]},

/* ============ 10. КЛАС ============ */
{klas:10, dom:'alg', title:'Ирационални изрази и ирационални уравнения', items:[
 {t:'O', h:'Ирационален израз', b:r`<p>Израз, в който неизвестната участва под знак за корен или в степен с дробен показател. <b>Допустими стойности</b> — тези, за които всички изрази имат смисъл.</p>`},
 {t:'P', h:'Условие за смисъл', b:r`<p>За да има смисъл $\sqrt{f(x)}$ в реалните числа, трябва $f(x)\ge0$.</p>`},
 {t:'P', h:'Уравнение с един радикал', b:r`<p>① Определи допустимите стойности. ② Изолирай радикала. ③ Повдигни на квадрат. ④ Реши полученото уравнение. ⑤ Направи проверка.</p>`},
 {t:'W', h:'Чужди корени', b:r`<p>Повдигането на квадрат може да въведе чужди корени — проверката в първоначалното уравнение е <b>задължителна</b>.</p>`},
 {t:'P', h:'Два радикала и полагане', b:r`<p>При два радикала: изолирай единия, повдигни на квадрат, изолирай втория, повдигни отново. При повтарящ се ирационален израз — въведи нова променлива (полагане) и накрая се върни към първоначалната.</p>`},
 {t:'Ex', h:'Пример', b:r`<p>$\sqrt{x+3}=x+1$: ДС $x\ge-1$; квадрат: $x+3=x^2+2x+1 \Rightarrow x^2+x-2=0 \Rightarrow x=1$ или $x=-2$ (отпада). Отговор: $x=1$.</p>`}
]},

{klas:10, dom:'alg', title:'Числови редици и прогресии', items:[
 {t:'O', h:'Числова редица', b:r`<p>Функция, дефинирана в множеството на естествените числа: $a_1,a_2,\dots,a_n,\dots$</p>`},
 {t:'O', h:'Аритметична прогресия', b:r`<p>Редица, при която разликата между всеки член след първия и предходния е постоянна: $d=a_{n+1}-a_n$.</p>`},
 {t:'F', h:'Аритметична прогресия — общ член и сбор', b:r`$$a_n=a_1+(n-1)d$$ $$S_n=\frac{n(a_1+a_n)}{2}=\frac{n\,(2a_1+(n-1)d)}{2}$$`},
 {t:'S', h:'Характеристично свойство (аритм.)', b:r`<p>Всеки член (без първия и последния) е средно аритметично на съседните: $a_n=\dfrac{a_{n-1}+a_{n+1}}{2}$.</p>`},
 {t:'Ex', h:'Пример (аритм.)', b:r`<p>$a_1=3,\ d=4$: $a_{10}=3+9\cdot4=39$; $S_{10}=\dfrac{10(3+39)}{2}=210$.</p>`},
 {t:'O', h:'Геометрична прогресия', b:r`<p>Редица с ненулеви членове, при която отношението на всеки член след първия към предходния е постоянно: $q=\dfrac{a_{n+1}}{a_n}$.</p>`},
 {t:'F', h:'Геометрична прогресия — общ член и сбор', b:r`$$a_n=a_1\cdot q^{\,n-1}$$ $$S_n=\frac{a_1(q^n-1)}{q-1}=\frac{a_1(1-q^n)}{1-q}\ (q\ne1) \qquad S_n=na_1\ (q=1)$$`},
 {t:'S', h:'Характеристично свойство (геом.)', b:r`<p>$a_n^2=a_{n-1}\cdot a_{n+1}$ за членове с еднакъв знак.</p>`},
 {t:'Ex', h:'Пример (геом.)', b:r`<p>$a_1=2,\ q=3$: $a_5=2\cdot3^4=162$; $S_5=\dfrac{2(3^5-1)}{3-1}=242$.</p>`},
 {t:'F', h:'Проста и сложна лихва', b:r`$$K=K_0\left(1+\frac{pn}{100}\right)\ \text{(проста)} \qquad K=K_0\left(1+\frac{p}{100}\right)^{\!n}\ \text{(сложна)}$$ <p>$p\%$ — лихва за един период, $n$ — брой периоди.</p>`},
 {model:'progr', h:'Модел: прогресии', b:'Избери вида, мести първия член и разликата/частното — стълбчетата показват първите n члена, а отдолу са a_n и S_n.'}
]},

{klas:10, dom:'prob', title:'Статистика и обработка на данни', items:[
 {t:'O', h:'Съвкупност и извадка', b:r`<p><b>Статистическа съвкупност</b> — множество от обекти, върху които се изследва признак. <b>Извадка</b> — част от съвкупността, избрана за наблюдение.</p>`},
 {t:'O', h:'Честота', b:r`<p><b>Честота</b> — брой наблюдения с дадена стойност; <b>относителна честота</b> — отношението ѝ към общия брой наблюдения.</p>`},
 {t:'O', h:'Мода и медиана', b:r`<p><b>Мода</b> — най-често срещаната стойност. <b>Медиана</b> — средната стойност в наредена извадка (при четен брой — средно аритметично на двете средни).</p>`},
 {t:'F', h:'Средно аритметично', b:r`$$\bar x=\frac{x_1+x_2+\dots+x_n}{n}$$`},
 {t:'O', h:'Петчислено представяне', b:r`<p>Минимум, първи квартил $Q_1$, медиана, трети квартил $Q_3$, максимум.</p>`},
 {t:'F', h:'Размах', b:r`$$R=x_{\max}-x_{\min} \qquad IQR=Q_3-Q_1$$`},
 {model:'stats', h:'Модел: статистика на данни', b:'Въведи свои числа — таблица на честотите, хистограма, полигон и всички основни числови характеристики.'}
]},

{klas:10, dom:'trig', title:'Тригонометрични функции в интервала [0°; 180°]', items:[
 {t:'O', h:'Определение чрез полуокръжност', b:r`<p>За ъгли от $0^\circ$ до $180^\circ$ синусът и косинусът се определят чрез координатите на точка от единичната полуокръжност.</p>`},
 {t:'W', h:'Знаци по квадранти', b:r`<p>В I квадрант $\sin,\cos,\tg,\cotg>0$; във II квадрант $\sin>0$, а $\cos,\tg,\cotg<0$.</p>`},
 {t:'F', h:'Формули за 180° − α', b:r`$$\sin(180^\circ-\alpha)=\sin\alpha \qquad \cos(180^\circ-\alpha)=-\cos\alpha$$ $$\tg(180^\circ-\alpha)=-\tg\alpha \qquad \cotg(180^\circ-\alpha)=-\cotg\alpha$$`},
 {t:'F', h:'Основни тъждества', b:r`$$\sin^2\alpha+\cos^2\alpha=1 \qquad \tg\alpha=\frac{\sin\alpha}{\cos\alpha} \qquad \cotg\alpha=\frac{\cos\alpha}{\sin\alpha} \qquad \tg\alpha\cdot\cotg\alpha=1$$`},
 {t:'W', h:'Недефинирани стойности', b:r`<p>$\tg\alpha$ не е дефиниран при $\alpha=90^\circ$; $\cotg\alpha$ — при $\alpha=0^\circ$ и $\alpha=180^\circ$.</p>`},
 {model:'semicircle', h:'Модел: единична полуокръжност', b:'Мести ъгъла от 0° до 180° — знаците на sin и cos по квадранти и формулата за 180° − α се виждат директно.'}
]},

{klas:10, dom:'geo', title:'Решаване на произволен триъгълник', items:[
 {t:'T', h:'Синусова теорема', b:r`$$\frac{a}{\sin A}=\frac{b}{\sin B}=\frac{c}{\sin C}=2R$$ <p>$R$ — радиус на описаната окръжност. <i>Използва се</i> при дадени страна и два ъгъла (или две страни и ъгъл срещу една от тях).</p>`},
 {t:'T', h:'Косинусова теорема', b:r`$$a^2=b^2+c^2-2bc\cos A$$ <p>(аналогично за $b^2$ и $c^2$). <i>Използва се</i> при две страни и ъгъл между тях или при три страни.</p>`},
 {t:'Ex', h:'Пример с косинусова теорема', b:r`<p>$b=5,\ c=8,\ A=60^\circ$: $a^2=25+64-2\cdot5\cdot8\cdot\tfrac12=49 \Rightarrow a=7$.</p>`},
 {t:'F', h:'Медиана и ъглополовяща', b:r`$$m_a=\frac12\sqrt{2b^2+2c^2-a^2} \qquad l_a=\sqrt{bc\left[1-\frac{a^2}{(b+c)^2}\right]}$$`},
 {t:'F', h:'Лице на триъгълник', b:r`$$S=\frac{a\,h_a}{2}=\frac{ab\sin C}{2}=\frac{bc\sin A}{2}=\frac{ca\sin B}{2}$$ $$S=\sqrt{p(p-a)(p-b)(p-c)},\quad p=\frac{a+b+c}{2}\ \text{(Херон)}$$ $$S=pr \qquad S=\frac{abc}{4R}$$`},
 {t:'P', h:'Коя теорема кога', b:r`<p>Страна + два ъгъла → синусова теорема. Две страни + ъгъл между тях, или три страни → косинусова теорема.</p>`},
 {model:'soltriangle', h:'Модел: решаване на триъгълник', b:'Задай две страни и ъгъла между тях — косинусовата и синусовата теорема дават третата страна, ъглите, лицето, R и r.'}
]},

{klas:10, dom:'geo', title:'Елементи от стереометрията', items:[
 {t:'O', h:'Прави и равнини в пространството', b:r`<p>Две прави могат да са пресичащи се, успоредни или <b>кръстосани</b>. Права и равнина: правата лежи в равнината, пресичат се в една точка, или правата е успоредна на равнината.</p>`},
 {t:'O', h:'Перпендикулярност', b:r`<p>Права е перпендикулярна на равнина, ако е перпендикулярна на всяка права от равнината през пресечната точка.</p>`},
 {t:'T', h:'Критерий за перпендикулярност', b:r`<p>Ако права е перпендикулярна на <b>две пресичащи се</b> прави от равнина, тя е перпендикулярна на равнината.</p>`},
 {t:'O', h:'Проекция и ъгли', b:r`<p><b>Ортогонална проекция</b> на точка — петата на перпендикуляра към равнината. <b>Ъгъл права–равнина</b> — между правата и проекцията ѝ. <b>Ъгъл между равнини</b> — между две прави, перпендикулярни на пресечницата, лежащи в двете равнини.</p>`},
 {model:'stereobasics', h:'Модел: основни понятия в пространството', b:'Завърти сцената чрез влачене и избери какво да се покаже: определяне на равнина, взаимно положение на прави / права и равнина / две равнини, и ъглите между тях.'},
 {t:'F', h:'Права призма', b:r`$$S_{\text{ок}}=P_{\text{осн}}\cdot h \qquad S_{\text{пълна}}=S_{\text{ок}}+2S_{\text{осн}} \qquad V=S_{\text{осн}}\cdot h$$ <p>Права призма — околните ръбове са перпендикулярни на основите.</p>`},
 {t:'F', h:'Пирамида', b:r`$$V=\frac{S_{\text{осн}}\cdot h}{3} \qquad S_{\text{ок}}=\frac{P_{\text{осн}}\cdot l}{2}\ \text{(правилна, } l\text{ — апотема)}$$`},
 {t:'F', h:'Цилиндър и конус', b:r`$$\text{Цилиндър: } S_{\text{ок}}=2\pi rh,\quad S_{\text{пълна}}=2\pi rh+2\pi r^2,\quad V=\pi r^2 h$$ $$\text{Конус: } S_{\text{ок}}=\pi rl,\quad S_{\text{пълна}}=\pi rl+\pi r^2,\quad V=\frac{\pi r^2h}{3},\quad l^2=r^2+h^2$$`},
 {t:'F', h:'Сфера и кълбо', b:r`$$S=4\pi R^2 \qquad V=\frac{4}{3}\pi R^3$$`},
 {t:'Ex', h:'Пример: конус', b:r`<p>$r=3,\ h=4$: $l=\sqrt{9+16}=5$, $S_{\text{ок}}=\pi\cdot3\cdot5=15\pi$, $V=\dfrac{\pi\cdot9\cdot4}{3}=12\pi$.</p>`},
 {model:'stereo', h:'Модел: тела в пространството', b:'Избери тяло, завърти го чрез влачене и построй височина, апотема, ъгъл между права и равнина или линеен ъгъл на двустенен ъгъл. Видимите ръбове са плътни, скритите — пунктирани.'}
]},

{klas:10, dom:'sum', title:'Справочник — 10. клас (най-важното)', items:[
 {t:'R', h:'Прогресии и ирационални уравнения', b:r`<p>Аритметична: $a_n=a_1+(n-1)d$, $S_n=\dfrac{n(a_1+a_n)}{2}$. Геометрична: $a_n=a_1q^{n-1}$, $S_n=\dfrac{a_1(q^n-1)}{q-1}$.</p><p>Ирационални уравнения: повдигаме на степен и <b>задължително проверяваме</b> корените (възможни външни).</p>`},
 {t:'R', h:'Решаване на произволен триъгълник', b:r`<p>Синусова: $\dfrac{a}{\sin A}=\dfrac{b}{\sin B}=\dfrac{c}{\sin C}=2R$. Косинусова: $a^2=b^2+c^2-2bc\cos A$.</p><p>Лице: $S=\dfrac12 ab\sin C=\sqrt{p(p-a)(p-b)(p-c)}$; $R=\dfrac{abc}{4S}$; $r=\dfrac{S}{p}$.</p>`},
 {t:'R', h:'Стереометрия — обеми и лица', b:r`<p>Призма: $V=S_{\text{осн}}h$. Пирамида: $V=\dfrac{S_{\text{осн}}h}{3}$. Цилиндър: $V=\pi r^2h$, $S=2\pi r(r+h)$.</p><p>Конус: $V=\dfrac{\pi r^2h}{3}$, $l=\sqrt{r^2+h^2}$. Сфера: $S=4\pi R^2$; кълбо: $V=\dfrac{4}{3}\pi R^3$.</p>`}
]},

/* ============ 11. КЛАС ============ */
{klas:11, dom:'alg', title:'Корени, степени и логаритми', items:[
 {t:'O', h:'Корен n-ти', b:r`<p>Корен $n$-ти от $a$ е число $x$, за което $x^n=a$. При четно $n$ и $a\ge0$ се разглежда неотрицателният корен.</p>`},
 {t:'F', h:'Свойства на корените', b:r`$$\sqrt[n]{ab}=\sqrt[n]{a}\cdot\sqrt[n]{b} \qquad \sqrt[n]{\frac{a}{b}}=\frac{\sqrt[n]{a}}{\sqrt[n]{b}}$$ $$\sqrt[n]{a^n}=|a|\ \text{(четно } n\text{)},\qquad \sqrt[n]{a^n}=a\ \text{(нечетно } n\text{)}$$`},
 {t:'O', h:'Степен с рационален показател', b:r`$$a^{m/n}=\sqrt[n]{a^m}=\left(\sqrt[n]{a}\right)^m,\quad a>0,\ n\in\mathbb N,\ n>1$$`},
 {t:'F', h:'Степенни свойства', b:r`$$a^p\cdot a^q=a^{p+q} \qquad \frac{a^p}{a^q}=a^{p-q} \qquad (a^p)^q=a^{pq}$$ $$(ab)^p=a^p b^p \qquad \left(\frac{a}{b}\right)^{\!p}=\frac{a^p}{b^p}$$`},
 {t:'O', h:'Показателна функция', b:r`<p>$y=a^x$, $a>0$, $a\ne1$. При $a>1$ — растяща; при $0<a<1$ — намаляваща. $D=\mathbb R$, $E=(0;+\infty)$.</p>`},
 {t:'O', h:'Логаритъм', b:r`<p>$\log_a b$ е показателят, на който се повдига основата $a$, за да се получи $b$: $$\log_a b=c \iff a^c=b, \qquad a>0,\ a\ne1,\ b>0$$</p>`},
 {t:'F', h:'Основни логаритмични тъждества', b:r`$$\log_a 1=0 \qquad \log_a a=1 \qquad a^{\log_a x}=x \qquad \log_a(a^x)=x$$`},
 {t:'F', h:'Свойства на логаритмите', b:r`$$\log_a(xy)=\log_a x+\log_a y \qquad \log_a\frac{x}{y}=\log_a x-\log_a y$$ $$\log_a(x^r)=r\log_a x \qquad \log_a b=\frac{\log_c b}{\log_c a}\ \text{(смяна на основата)}$$`},
 {t:'Ex', h:'Пример с логаритми', b:r`<p>$\log_2 40-\log_2 5=\log_2\dfrac{40}{5}=\log_2 8=3$.</p>`},
 {t:'O', h:'Логаритмична функция', b:r`<p>$y=\log_a x$ е обратна на $y=a^x$: $D=(0;+\infty)$, $E=\mathbb R$.</p>`},
 {model:'explog', h:'Модел: показателна и логаритмична функция', b:'Мести основата a — графиките на y = aˣ и y = logₐx са симетрични спрямо правата y = x.'}
]},

{klas:11, dom:'geo', title:'Решаване на равнинни фигури', items:[
 {t:'F', h:'Успоредник и ромб', b:r`$$\text{Успоредник: } S=a\,h_a=b\,h_b=ab\sin\alpha$$ $$\text{Ромб: } S=a\,h=\frac{d_1 d_2}{2}=a^2\sin\alpha$$ <p>Диагоналите на успоредника се разполовяват.</p>`},
 {t:'F', h:'Правоъгълник и квадрат', b:r`$$\text{Правоъгълник: } S=ab,\quad d=\sqrt{a^2+b^2}$$ $$\text{Квадрат: } S=a^2,\quad d=a\sqrt2$$`},
 {t:'F', h:'Трапец', b:r`$$S=\frac{(a+b)\,h}{2} \qquad m=\frac{a+b}{2}$$`},
 {t:'S', h:'Равнобедрен трапец', b:r`<p>Бедрата са равни, ъглите при всяка основа са равни, диагоналите са равни.</p>`},
 {t:'F', h:'Правилен многоъгълник', b:r`$$\text{централен ъгъл}=\frac{360^\circ}{n} \qquad \text{вътрешен ъгъл}=\frac{(n-2)\cdot180^\circ}{n} \qquad S=\frac{P\cdot r}{2}$$ <p>$r$ — апотема.</p>`},
 {t:'P', h:'Общ подход', b:r`<p>Фигурата се свежда до триъгълници чрез диагонали, височини, средни отсечки и допълнителни построения.</p>`},
 {model:'planefigs', h:'Модел: равнинни фигури', b:'Избери фигура и променяй елементите ѝ — лице, диагонали и ъгли се пресмятат динамично.'}
]},

{klas:11, dom:'trig', title:'Обобщен ъгъл, радиан и тригонометрични функции', items:[
 {t:'O', h:'Обобщен ъгъл', b:r`<p>Може да има произволна реална мярка; положителната посока е обратно на часовниковата стрелка.</p>`},
 {t:'O', h:'Радиан', b:r`<p>Мярката на централен ъгъл, отсичащ дъга с дължина, равна на радиуса.</p>`},
 {t:'F', h:'Градуси и радиани', b:r`$$180^\circ=\pi\ \text{rad} \qquad 1^\circ=\frac{\pi}{180}\ \text{rad} \qquad 1\ \text{rad}=\frac{180^\circ}{\pi}$$`},
 {t:'O', h:'Определение чрез единичната окръжност', b:r`<p>$\cos x$ е абсцисата, а $\sin x$ — ординатата на съответната точка от единичната окръжност. $$\tg x=\frac{\sin x}{\cos x}\ (\cos x\ne0) \qquad \cotg x=\frac{\cos x}{\sin x}\ (\sin x\ne0)$$</p>`},
 {t:'F', h:'Основни тъждества', b:r`$$\sin^2x+\cos^2x=1 \qquad 1+\tg^2x=\frac{1}{\cos^2x} \qquad 1+\cotg^2x=\frac{1}{\sin^2x}$$`},
 {t:'S', h:'Периодичност и четност', b:r`<p>$\sin x,\ \cos x$ — период $2\pi$; $\tg x,\ \cotg x$ — период $\pi$. $\sin x,\ \tg x,\ \cotg x$ са нечетни; $\cos x$ е четна.</p>`},
 {t:'O', h:'Четна, нечетна, периодична функция', b:r`<p>Четна: $f(-x)=f(x)$; нечетна: $f(-x)=-f(x)$; периодична с период $T$: $f(x+T)=f(x)$.</p>`},
 {model:'unitcircle', h:'Модел: единична окръжност и графики', b:'Пусни точката да се движи по окръжността и наблюдавай как се раждат графиките на sin x и cos x.'}
]},

{klas:11, dom:'trig', title:'Графики на тригонометричните функции', items:[
 {t:'S', h:'y = sin x', b:r`<p>$D=\mathbb R$, $E=[-1;1]$, период $2\pi$; нули $x=k\pi$; максимуми $1$ при $x=\tfrac{\pi}{2}+2k\pi$; минимуми $-1$ при $x=\tfrac{3\pi}{2}+2k\pi$.</p>`},
 {t:'S', h:'y = cos x', b:r`<p>$D=\mathbb R$, $E=[-1;1]$, период $2\pi$; нули $x=\tfrac{\pi}{2}+k\pi$; максимуми $1$ при $x=2k\pi$; минимуми $-1$ при $x=\pi+2k\pi$.</p>`},
 {t:'S', h:'y = tg x', b:r`<p>$D=\mathbb R\setminus\{\tfrac{\pi}{2}+k\pi\}$, $E=\mathbb R$, период $\pi$; нули $x=k\pi$; вертикални асимптоти $x=\tfrac{\pi}{2}+k\pi$.</p>`},
 {t:'S', h:'y = cotg x', b:r`<p>$D=\mathbb R\setminus\{k\pi\}$, $E=\mathbb R$, период $\pi$; нули $x=\tfrac{\pi}{2}+k\pi$; вертикални асимптоти $x=k\pi$.</p>`},
 {model:'triggraphs', h:'Модел: графики на sin, cos, tg и cotg', b:'Избери функция — нули, период и вертикални асимптоти директно върху графиката.'}
]},

{klas:11, dom:'trig', title:'Тригонометрични формули', items:[
 {t:'F', h:'Сбор и разлика на ъгли', b:r`$$\sin(\alpha\pm\beta)=\sin\alpha\cos\beta\pm\cos\alpha\sin\beta$$ $$\cos(\alpha\pm\beta)=\cos\alpha\cos\beta\mp\sin\alpha\sin\beta$$ $$\tg(\alpha\pm\beta)=\frac{\tg\alpha\pm\tg\beta}{1\mp\tg\alpha\,\tg\beta}$$`},
 {t:'F', h:'Двоен ъгъл', b:r`$$\sin2\alpha=2\sin\alpha\cos\alpha$$ $$\cos2\alpha=\cos^2\alpha-\sin^2\alpha=2\cos^2\alpha-1=1-2\sin^2\alpha$$ $$\tg2\alpha=\frac{2\tg\alpha}{1-\tg^2\alpha}$$`},
 {t:'F', h:'Половинка на ъгъл', b:r`$$\sin^2\frac{\alpha}{2}=\frac{1-\cos\alpha}{2} \qquad \cos^2\frac{\alpha}{2}=\frac{1+\cos\alpha}{2}$$`},
 {t:'F', h:'Сбор в произведение', b:r`$$\sin\alpha+\sin\beta=2\sin\frac{\alpha+\beta}{2}\cos\frac{\alpha-\beta}{2} \qquad \sin\alpha-\sin\beta=2\cos\frac{\alpha+\beta}{2}\sin\frac{\alpha-\beta}{2}$$ $$\cos\alpha+\cos\beta=2\cos\frac{\alpha+\beta}{2}\cos\frac{\alpha-\beta}{2} \qquad \cos\alpha-\cos\beta=-2\sin\frac{\alpha+\beta}{2}\sin\frac{\alpha-\beta}{2}$$`},
 {t:'F', h:'Произведение в сбор', b:r`$$2\sin\alpha\cos\beta=\sin(\alpha+\beta)+\sin(\alpha-\beta)$$ $$2\cos\alpha\cos\beta=\cos(\alpha+\beta)+\cos(\alpha-\beta)$$ $$2\sin\alpha\sin\beta=\cos(\alpha-\beta)-\cos(\alpha+\beta)$$`},
 {t:'Ex', h:'Пример: cos 75°', b:r`<p>$\cos75^\circ=\cos(45^\circ+30^\circ)=\dfrac{\sqrt2}{2}\cdot\dfrac{\sqrt3}{2}-\dfrac{\sqrt2}{2}\cdot\dfrac12=\dfrac{\sqrt6-\sqrt2}{4}$.</p>`}
]},

{klas:11, dom:'prob', title:'Вероятности', items:[
 {t:'O', h:'Условна вероятност', b:r`<p>Вероятността за $A$ при условие, че $B$ е настъпило: $$P(A\mid B)=\frac{P(A\cap B)}{P(B)},\quad P(B)>0$$</p>`},
 {t:'T', h:'Теорема за умножение', b:r`$$P(A\cap B)=P(B)\,P(A\mid B)=P(A)\,P(B\mid A)$$`},
 {t:'O', h:'Независими събития', b:r`<p>$A$ и $B$ са независими, ако $P(A\cap B)=P(A)\,P(B)$; еквивалентно $P(A\mid B)=P(A)$ при $P(B)>0$.</p>`},
 {t:'O', h:'Схема на Бернули', b:r`<p>Многократен експеримент с два изхода, при който опитите са независими и вероятността $p$ за успех е постоянна.</p>`},
 {t:'F', h:'Формула на Бернули', b:r`<p>Вероятност за точно $k$ успеха в $n$ независими опита: $$P=C_n^k\,p^k(1-p)^{\,n-k}$$</p>`},
 {t:'Ex', h:'Пример с Бернули', b:r`<p>3 хвърляния на монета, точно 2 герба: $P=C_3^2\left(\tfrac12\right)^2\!\left(\tfrac12\right)=\dfrac{3}{8}$.</p>`},
 {t:'O', h:'Разпределение на вероятностите', b:r`<p>Задава възможните стойности на случайна величина и вероятностите им; сумата на вероятностите е $1$.</p>`},
 {t:'O', h:'Геометрична вероятност', b:r`<p>Върху отсечка/област — отношение на дължини/лица при равномерно избиране.</p>`},
 {model:'bernoulli', h:'Модел: схема на Бернули', b:'Задай n и p — разпределението на броя успехи като стълбчета; избери k, за да видиш точната формула с числа.'}
]},

{klas:11, dom:'sum', title:'Справочник — 11. клас (най-важното)', items:[
 {t:'R', h:'Степени, корени и логаритми', b:r`<p>$a^m\cdot a^n=a^{m+n}$, $\dfrac{a^m}{a^n}=a^{m-n}$, $(a^m)^n=a^{mn}$, $a^{1/n}=\sqrt[n]{a}$.</p><p>$\log_a(xy)=\log_a x+\log_a y$, $\ \log_a\dfrac{x}{y}=\log_a x-\log_a y$, $\ \log_a x^n=n\log_a x$, $\ \log_a x=\dfrac{\log_b x}{\log_b a}$.</p>`},
 {t:'R', h:'Показателна, логаритмична и тригонометрия', b:r`<p>$y=a^x$ и $y=\log_a x$ са взаимно обратни (симетрични спрямо $y=x$); растящи при $a>1$, намаляващи при $0<a<1$.</p><p>Радиан: $\pi\text{ rad}=180^\circ$. Основно тъждество: $\sin^2\alpha+\cos^2\alpha=1$, $\ \tg\alpha=\dfrac{\sin\alpha}{\cos\alpha}$.</p>`},
 {t:'R', h:'Тригонометрични формули', b:r`<p>$\sin(\alpha\pm\beta)=\sin\alpha\cos\beta\pm\cos\alpha\sin\beta$; $\ \cos(\alpha\pm\beta)=\cos\alpha\cos\beta\mp\sin\alpha\sin\beta$.</p><p>Двоен ъгъл: $\sin2\alpha=2\sin\alpha\cos\alpha$, $\ \cos2\alpha=\cos^2\alpha-\sin^2\alpha$.</p>`}
]},

/* ============ 12. КЛАС ============ */
{klas:12, dom:'prob', title:'Статистика', items:[
 {t:'O', h:'Групирани данни и хистограма', b:r`<p><b>Групирани данни</b> — обединени в интервали, за които се записват честоти. <b>Хистограма</b> — правоъгълници, чиито височини показват честоти или честотни плътности.</p>`},
 {t:'O', h:'Полигон и акумулирана честота', b:r`<p><b>Полигон на честотите</b> — начупена линия през средите на интервалите и честотите им. <b>Акумулирана честота</b> — сумата от честотите до дадена стойност включително.</p>`},
 {t:'F', h:'Средна стойност за честотна таблица', b:r`$$\bar x=\frac{x_1n_1+x_2n_2+\dots+x_kn_k}{n_1+n_2+\dots+n_k}$$`},
 {t:'O', h:'Дисперсия', b:r`<p>Мярка за средното квадратично отклонение от средната стойност.</p>`},
 {t:'F', h:'Дисперсия и стандартно отклонение', b:r`$$s^2=\frac{(x_1-\bar x)^2+\dots+(x_n-\bar x)^2}{n} \qquad s=\sqrt{s^2}$$`},
 {t:'O', h:'Статистическа честота и оценка на дял', b:r`<p>Статистическа честота на събитие — отношение на настъпванията към броя опити. Оценка на неизвестен дял: $\hat p=\dfrac{m}{n}$.</p>`},
 {t:'W', h:'Надеждност', b:r`<p>Колкото по-голяма и по-представителна е извадката, толкова по-надеждна е оценката.</p>`},
 {model:'stats', h:'Модел: хистограма и характеристики', b:'Въведи данни и разгледай хистограма, полигон, средно, медиана, мода, размах и стандартно отклонение.'}
]},

{klas:12, dom:'alg', title:'Уравнения', items:[
 {t:'P', h:'Модулно уравнение', b:r`<p>$|F(x)|=m$: при $m<0$ — няма решение; при $m=0$ — $F(x)=0$; при $m>0$ — $F(x)=m$ или $F(x)=-m$.</p>`},
 {t:'P', h:'Показателни уравнения', b:r`<p>$a^{f(x)}=a^{g(x)}$ при $a>0,\ a\ne1$ $\Rightarrow f(x)=g(x)$. Уравнения от вида $a^{2u}+b\,a^u+c=0$ се решават с полагане $t=a^u>0$.</p>`},
 {t:'P', h:'Логаритмични уравнения', b:r`<p>Изискват положителни аргументи и допустима основа; след решаване се проверява ДС: $$\log_a F(x)=\log_a G(x)\iff F(x)=G(x)\ \ (F,G>0)$$ $$\log_a F(x)=m\iff F(x)=a^m\ \ (F(x)>0)$$</p>`},
 {t:'F', h:'Основни тригонометрични уравнения', b:r`$$\sin x=a\ (|a|\le1):\quad x=(-1)^k\arcsin a+k\pi,\ k\in\mathbb Z$$ $$\cos x=a\ (|a|\le1):\quad x=\pm\arccos a+2k\pi,\ k\in\mathbb Z$$ $$\tg x=a:\quad x=\arctg a+k\pi \qquad \cotg x=a:\quad x=\arcctg a+k\pi$$`},
 {t:'Ex', h:'Пример: sin x = 1/2', b:r`<p>$x=(-1)^k\dfrac{\pi}{6}+k\pi,\ k\in\mathbb Z$, т.е. сериите $\dfrac{\pi}{6}+2k\pi$ и $\dfrac{5\pi}{6}+2k\pi$.</p>`},
 {t:'P', h:'Свеждане до квадратни', b:r`<p>Тригонометрични уравнения често се решават с полагане $t=\sin x$, $t=\cos x$, $t=\tg x$ или чрез формулите за преобразуване.</p>`}
]},

{klas:12, dom:'alg', title:'Неравенства', items:[
 {t:'P', h:'Модулни неравенства', b:r`<p>$|F(x)|<m$ при $m>0$ $\iff -m<F(x)<m$; при $m\le0$ — няма решение (за $\le$ и $m=0$: $F(x)=0$). $|F(x)|>m$ при $m>0$ $\iff F(x)<-m$ или $F(x)>m$; при $m<0$ е вярно за всички допустими $x$.</p>`},
 {t:'P', h:'Ирационални неравенства', b:r`<p>$\sqrt{F(x)}$ изисква $F(x)\ge0$. $$\sqrt{F(x)}<G(x)\iff F(x)\ge0,\ G(x)>0,\ F(x)<G^2(x)$$ $$\sqrt{F(x)}>G(x):\ \text{при } G(x)<0,\ F(x)\ge0\ \text{— вярно; при } G(x)\ge0\ \text{— } F(x)>G^2(x)$$</p>`},
 {t:'P', h:'Показателни неравенства', b:r`<p>$a^{f(x)}>a^{g(x)}$: при $a>1$ $\Rightarrow f(x)>g(x)$; при $0<a<1$ знакът се обръща: $f(x)<g(x)$.</p>`},
 {t:'P', h:'Логаритмични неравенства', b:r`<p>$\log_a F(x)>\log_a G(x)$: при $a>1$ — $F(x)>G(x)$; при $0<a<1$ — $F(x)<G(x)$, като винаги $F(x)>0$ и $G(x)>0$.</p>`},
 {t:'W', h:'Най-чести грешки', b:r`<p>Пропуснати ДС, включени нули на знаменател, необърнат знак при основа между $0$ и $1$.</p>`},
 {t:'W', h:'Задължителни проверки по тип', b:r`<p><b>Ирационално:</b> подкоренни изрази $\ge0$; проверка след квадрат. <b>Логаритмично:</b> аргументи $>0$, основа $>0$ и $\ne1$. <b>Дробно:</b> знаменатели $\ne0$. <b>Показателно:</b> знакът зависи от основата. <b>Тригонометрично:</b> периодът и всички серии решения. <b>Модулно:</b> случаи според знака.</p>`}
]},

{klas:12, dom:'alg', title:'Екстремални задачи', items:[
 {t:'O', h:'Екстремална задача', b:r`<p>Задача за намиране на най-голяма или най-малка стойност на величина при дадени условия.</p>`},
 {t:'F', h:'Линейна функция в интервал', b:r`<p>$f(x)=ax+b$ в затворен интервал $[m;n]$ приема най-голямата и най-малката си стойност в <b>краищата</b> на интервала.</p>`},
 {t:'F', h:'Квадратна функция и връх', b:r`<p>$f(x)=ax^2+bx+c$ има връх при $x_0=-\dfrac{b}{2a}$. При $a>0$ — минимум във върха; при $a<0$ — максимум.</p>`},
 {t:'P', h:'Квадратна функция в затворен интервал', b:r`<p>Проверяват се стойностите в краищата и във върха, ако $x_0$ принадлежи на интервала.</p>`},
 {t:'T', h:'Средно аритметично ≥ средно геометрично', b:r`<p>За $a\ge0,\ b\ge0$: $$\frac{a+b}{2}\ge\sqrt{ab}$$ с равенство при $a=b$. <i>Използва се</i> за оценки без производни.</p>`},
 {t:'S', h:'Следствия', b:r`<p>При постоянна сума на две положителни величини произведението им е най-голямо при равни величини. При постоянен периметър правоъгълникът с най-голямо лице е квадратът.</p>`},
 {t:'P', h:'Подходи', b:r`<p><b>Алгебричен:</b> изрази величината чрез една променлива, определи допустимите стойности, намери екстремума. <b>Геометричен:</b> симетрия, неравенства, познати формули, свеждане до функция на една променлива.</p>`},
 {t:'W', h:'Пълен отговор', b:r`<p>Отговорът съдържа не само екстремалната стойност, но и условията, при които се достига.</p>`},
 {t:'Ex', h:'Пример', b:r`<p>Правоъгълник с периметър $20$: $a+b=10$, $S=ab\le\left(\dfrac{10}{2}\right)^2=25$ — максимум при квадрат $5\times5$.</p>`},
 {model:'quad', h:'Модел: екстремум на квадратна функция', b:'Мести коефициентите и наблюдавай върха — минимум при a > 0, максимум при a < 0.'}
]},
{klas:12, dom:'sum', title:'Справочник — 12. клас (най-важното)', items:[
 {t:'R', h:'Тригонометрични уравнения', b:r`<p>$\sin x=a\Rightarrow x=(-1)^k\arcsin a+k\pi$; $\ \cos x=a\Rightarrow x=\pm\arccos a+2k\pi$; $\ \tg x=a\Rightarrow x=\arctg a+k\pi$ ($k\in\mathbb{Z}$).</p><p>При показателни и логаритмични уравнения не забравяй <b>ОДЗ</b>.</p>`},
 {t:'R', h:'Комбинаторика и вероятност', b:r`<p>$P_n=n!$; $\ V_n^k=\dfrac{n!}{(n-k)!}$; $\ C_n^k=\dfrac{n!}{k!(n-k)!}$.</p><p>Класическа вероятност $P=\dfrac{\text{благоприятни}}{\text{всички}}$; $\ P(A\cup B)=P(A)+P(B)-P(A\cap B)$; Бернули: $P(X=k)=C_n^k p^k(1-p)^{n-k}$.</p>`},
 {t:'R', h:'Статистика и екстремуми', b:r`<p>Средно аритметично, медиана, мода, размах и стандартно отклонение описват набор от данни.</p><p>Екстремални задачи: минимум/максимум чрез връх на парабола ($x=-\dfrac{b}{2a}$) или чрез изследване с производна.</p>`}
]},
];
